185		-- *** Level Check ***
186		procedure LevelCheck(	Expected	: in	std_logic;
187								signal Sig	: in	std_logic;
188								Msg			: in	MsgInfo_r;
189								GeneralMsg	: in	string) is
190		begin
191			-- Do not check for other inputs than 1 or 0
192			if (Expected = '0') or (Expected = '1') then
193				assert ((Expected = '0') and (Sig = '0')) or ((Expected = '1') and ((Sig = '1') or (Sig = 'H')))
194					report GenMessage(Msg.Prefix, Msg.Func, GeneralMsg, Msg.User)
195					severity error;
196			end if;
197		end procedure;
198		
199		procedure LevelWait(	Expected	: in	std_logic;
200								signal Sig	: in	std_logic;
201								Timeout		: in	time;
202								Msg			: in	MsgInfo_r;
203								GeneralMsg	: in	string) is
204			variable Correct_v : boolean;
205		begin
206			if Sig /= Expected then
207				if Expected = '0' then
208					wait until Sig = '0' for Timeout;
209					Correct_v := (Sig = '0');
210				else
211					wait until (Sig = '1') or (Sig = 'H') for Timeout;
212					Correct_v := ((Sig = '1') or (Sig = 'H'));
213				end if;
214				assert Correct_v 
215					report GenMessage(Msg.Prefix, Msg.Func, GeneralMsg, Msg.User)
216					severity error;
217			end if;
218		end procedure;
