289		procedure SendBitExclClock(		Data			: in	std_logic;
290										signal Scl		: inout std_logic;
291										signal Sda		: inout std_logic;
292										Timeout			: in	time;
293										BitInfo			: in	string;
294										Msg				: in 	MsgInfo_r;
295										ClockStretch	: in	time) is	
296			variable Stretched_v : boolean := false;
297		begin
298			-- Initial Check
299			LevelCheck('0', Scl, Msg, "SCL must be 0 before SendBitExclClock is called");
300			
301			-- Clock stretching
302			if ClockStretch > 0 ns then
303				Scl <= '0';
304				wait for ClockStretch;
305				Stretched_v := true;
306			end if;
307			
308			-- Assert Data		
309			if Data = '0' then
310				Sda <= '0';
311			else
312				Sda <= 'Z';
313			end if;	
314			if Stretched_v then
315				wait for ClkQuartPeriod;
316				Scl <= 'Z';
317			end if;
318			
319			-- Wait clock rising edge
320			LevelWait('1', Scl, Timeout, Msg, "SCL did not go high");
321			
322			-- wait clock falling edge
323			LevelWait('0', Scl, Timeout, Msg, "SCL did not go low");
324			LevelCheck(Data, Sda, Msg, "Received wrong data [" & BitInfo & "]");
325			CheckLastActivity(Sda, ClkHalfPeriod, -1, GenMessageNoPrefix(Msg.Func, "SDA not stable during SCL pulse [" & BitInfo & "]", Msg.User), Msg.Prefix);
326			
327			-- wait until center of low
328			wait for ClkQuartPeriod;
329		end procedure;		
