331		procedure CheckBitExclClock(	Data			: in	std_logic;
332										signal Scl		: inout std_logic;
333										signal Sda		: inout std_logic;
334										Timeout			: in	time;
335										BitInfo			: in	string;
336										Msg				: in 	MsgInfo_r;
337										ClockStretch	: in	time) is	
338		begin
339			-- Initial Check
340			LevelCheck('0', Scl, Msg, "SCL must be 0 before CheckBitExclClock is called");
341			
342			-- Wait clock rising edge
343			if ClockStretch > 0 ns then
344				Scl <= '0';
345				wait for ClockStretch;
346				Scl <= 'Z';
347			end if;		
348			LevelWait('1', Scl, Timeout, Msg, "SCL did not go high");
349			
350			-- wait clock falling edge
351			LevelWait('0', Scl, Timeout, Msg, "SCL did not go low");
352			LevelCheck(Data, Sda, Msg, "Received wrong data [" & BitInfo & "]");
353			CheckLastActivity(Sda, ClkHalfPeriod, -1, GenMessageNoPrefix(Msg.Func, "SDA not stable during SCL pulse [" & BitInfo & "]", Msg.User), Msg.Prefix);
354			
355			-- wait until center of low
356			wait for ClkQuartPeriod;
357		end procedure;	
