498		procedure I2cMasterSendAddr(	Address 	: in	integer;
499										IsRead		: in	boolean;
500										signal Scl	: inout std_logic;
501										signal Sda	: inout std_logic;
502										Msg			: in 	string		:= "No Msg";
503										AddrBits	: in	integer		:= 7;		-- 7 or 10
504										ExpectedAck	: in 	std_logic	:= '0';		-- '0' for ack, '1' for nack, anything else for "don't check"
505										Prefix		: in 	string		:= "###ERROR###: ") is	
506			constant AddrSlv_c 	: std_logic_vector(9 downto 0) := std_logic_vector(to_unsigned(Address, 10));
507			constant Rw_c 		: std_logic		:= choose(IsRead, '1', '0');
508		begin
509			-- 7 Bit addressing
510			if AddrBits = 7 then
511				SendByteInclClock(AddrSlv_c(6 downto 0) & Rw_c, Scl, Sda, (Prefix, "I2cMasterSendAddr 7b", Msg));
512				Sda <= 'Z';
513				CheckBitInclClock(ExpectedAck, Scl, Sda, "ACK", (Prefix, "I2cMasterSendAddr 7b", Msg));
514			-- 10 Bit addressing
515			elsif AddrBits = 10 then
516				SendByteInclClock("11110" & AddrSlv_c(9 downto 8) & Rw_c, Scl, Sda, (Prefix, "I2cMasterSendAddr 10b 9:8", Msg));
517				Sda <= 'Z';
518				CheckBitInclClock(ExpectedAck, Scl, Sda, "ACK", (Prefix, "I2cMasterSendAddr 10b 9:8", Msg));
519				SendByteInclClock(AddrSlv_c(7 downto 0), Scl, Sda, (Prefix, "I2cMasterSendAddr 10b 7:0", Msg));
520				Sda <= 'Z';
521				CheckBitInclClock(ExpectedAck, Scl, Sda, "ACK", (Prefix, "I2cMasterSendAddr 10b 7:0", Msg));
522			else
523				report Prefix & "I2cMasterSendAddr - Illegal addrBits (must be 7 or 10) - " & Msg severity error;
524			end if;
525		end procedure;
