527		procedure I2cMasterSendByte(	Data 		: in	integer range -128 to 255;
528										signal Scl	: inout std_logic;
529										signal Sda	: inout std_logic;
530										Msg			: in 	string		:= "No Msg";
531										ExpectedAck	: in 	std_logic	:= '0';		-- '0' for ack, '1' for nack, anything else for "don't check"
532										Prefix		: in 	string		:= "###ERROR###: ") is	
533			variable DataSlv_v : std_logic_vector(7 downto 0);
534		begin
535			-- Do data
536			if Data < 0 then
537				DataSlv_v := std_logic_vector(to_signed(Data, 8));
538			else
539				DataSlv_v := std_logic_vector(to_unsigned(Data, 8));
540			end if;
541			SendByteInclClock(DataSlv_v, Scl, Sda, (Prefix, "I2cMasterSendByte", Msg));
542			Sda <= 'Z';
543			CheckBitInclClock(ExpectedAck, Scl, Sda, "ACK", (Prefix, "I2cMasterSendByte", Msg));			
544		end procedure;
