547		procedure I2cMasterExpectByte(	ExpData		: in	integer range -128 to 255;
548										signal Scl	: inout std_logic;
549										signal Sda	: inout std_logic;
550										Msg			: in 	string		:= "No Msg";
551										AckOutput	: in 	std_logic	:= '0';		-- '0' for ack, '1' for nack	
552										Prefix		: in 	string		:= "###ERROR###: ") is
553			variable Data_v 	: std_logic_vector(7 downto 0);
554		begin
555			-- Convert data
556			if ExpData < 0 then
