425	      variable l: character;
426	   begin
427	      case c is
428	           when 'A' => l:='a';
429	           when 'B' => l:='b';
430	           when 'C' => l:='c';
431	           when 'D' => l:='d';
432	           when 'E' => l:='e';
433	           when 'F' => l:='f';
