484	      variable sl : std_logic;
485	   begin
486	      case c is
487	           when 'U' =>
488	                sl:='U';
489	           when 'X' =>
490	                sl:='X';
491	           when '0' => 
492	                sl:='0';
493	           when '1' => 
494	                sl:='1';
495	           when 'Z' => 
496	                sl:='Z';
497	           when 'W' => 
498	                sl:='W';
499	           when 'L' => 
