		I2cMasterExpectByte(16#CD#, scl, sda, "M: data-read", '1');
		I2cMasterSendStop(scl, sda, "M: stop");
		wait for 10 us;

		-- Single Byte Write, ACK
		print("Single Byte Write, ACK");
